import{_ as r,o as t,c as _,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const m=JSON.parse('{"title":"工业产物——秘密的日记本","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/工业产物——秘密的日记本.md","filePath":"4.资源分区/7.物品与装备/4.奇物/1.D级/工业产物——秘密的日记本.md"}'),n={name:"4.资源分区/7.物品与装备/4.奇物/1.D级/工业产物——秘密的日记本.md"};function d(i,a,l,p,c,h){return t(),_("div",null,[...a[0]||(a[0]=[e("h1",{id:"工业产物——秘密的日记本",tabindex:"-1"},[s("工业产物——秘密的日记本 "),e("a",{class:"header-anchor",href:"#工业产物——秘密的日记本","aria-label":'Permalink to "工业产物——秘密的日记本"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调018")])])],-1),o('<h1 id="工业产物秘密的日记本" tabindex="-1">工业产物秘密的日记本 <a class="header-anchor" href="#工业产物秘密的日记本" aria-label="Permalink to &quot;工业产物秘密的日记本&quot;">​</a></h1><p>秘密的日记本 (Secret Diary)<br> 等级: D+500<br> 描述:<br> 一本封面沾染了暗红色的旧日记本，暗红色的污渍略微侵染了微微泛黄的纸张，它似乎已经被放置了很长的时间。这本日记中的每一页都记录着少女之间的秘密对话和不为人知的青春悸动，一些未曾言明的感情在词句间悄然流淌。不过，这些字迹仅能被心怀相似情感的人所解读，其他人看到的不过是空白的纸页。日记本中夹杂着一朵早已风干的花朵，那正是少女们曾经关系的见证。</p><p>效果:<br> 心灵之桥 (Bridge of Hearts)<br> 每一笔墨痕，都是她们未曾说出口的情话。它们横跨心灵，将两颗心拉近。<br> 佩戴者可以通过日记本与他人建立心灵感应，无需言语便能彼此理解心意。这个能力适用于与佩戴者关系紧密的人，使用者可以在笔记本上记下对某人想传递的心意，之后这份心意将直抵对方的内心，由此日记本传递的内容不会携带具体的文字信息，但却能真切传递相互之间的情感，这意味着即使双方即使语言不通，亦会能通过情感理解彼此的心意。<br> 使用日记本对其他人第一次传递心意时，需要见到对方并在笔记本上写下内容，如果对方接受了这份心意，之后只需要笔记本在其中一方的身边即可完成交流，并且经由日记本建立的交流将不会受到距离的限制，这视为一个D级的通讯能力。</p><p>浮现的记忆 (Emergent Memories)<br> 她们最后的记忆被保存在了这里，只需翻开日记，便能重现那些已经消逝的时光。<br> 当使用者集中精神时，日记本的页面会浮现出片段般的记忆，重现某个场景中的情感线索，帮助佩戴者解开某种困惑或找到遗失的东西。这种能力可以短暂地追溯近期发生的事件，但无法窥探未来。每天最多1次，从后向前翻开日记本，在书页的翻动中周围的场景会逐渐倒流，你能浏览最多到一小时前的场景，并能在这拾遗中探查到人们那时心中的情感（仍需正常与那个状态的人进行对抗），整个过程持续一小时的时间。这同时视为一个C级的信息回溯与D级读心能力。</p><hr><p>Copyright ? 2024 TMDtrpg制作组. All Rights Reserved.</p>',6)])])}const f=r(n,[["render",d]]);export{m as __pageData,f as default};
